import {
	InternalCompressedStream,
	normalizeSize,
	toUint8Array,
} from './compressed-stream.js';

const XZ_OK = 0;
const XZ_STREAM_END = 1;
const XZ_STREAM_FOOTER_SIZE = 12;
const XZ_INDEX_INDICATOR = 0x00;
const XZ_FOOTER_MAGIC_Y = 0x59;
const XZ_FOOTER_MAGIC_Z = 0x5a;
const XZ_VLI_MAX_BYTES = 9;

const XZ_WASM_BASE64 = '';

function readUint32LE(bytes, offset) {
	if (!bytes || offset < 0 || bytes.byteLength < offset + 4) {
		return null;
	}
	return (
		(bytes[offset])
		| (bytes[offset + 1] << 8)
		| (bytes[offset + 2] << 16)
		| (bytes[offset + 3] << 24)
	) >>> 0;
}

function parseXzVli(bytes, offset) {
	if (!bytes || offset < 0 || offset >= bytes.byteLength) {
		return null;
	}

	let value = 0n;
	let shift = 0n;
	let cursor = offset;

	for (let index = 0; index < XZ_VLI_MAX_BYTES && cursor < bytes.byteLength; index++, cursor++) {
		const byte = bytes[cursor];
		value |= BigInt(byte & 0x7f) << shift;

		if ((byte & 0x80) === 0) {
			if (value > BigInt(Number.MAX_SAFE_INTEGER)) {
				return null;
			}
			return {
				value: Number(value),
				nextOffset: cursor + 1,
			};
		}

		shift += 7n;
	}

	return null;
}

function parseXzIndexUncompressedSize(indexBytes) {
	if (!indexBytes || indexBytes.byteLength < 8) {
		return null;
	}

	const crcOffset = indexBytes.byteLength - 4;
	if (indexBytes[0] !== XZ_INDEX_INDICATOR) {
		return null;
	}

	let cursor = 1;
	const recordCountResult = parseXzVli(indexBytes, cursor);
	if (!recordCountResult) {
		return null;
	}

	const recordCount = recordCountResult.value;
	cursor = recordCountResult.nextOffset;

	let uncompressedTotal = 0;
	for (let index = 0; index < recordCount; index++) {
		const unpaddedSizeResult = parseXzVli(indexBytes, cursor);
		if (!unpaddedSizeResult) {
			return null;
		}
		cursor = unpaddedSizeResult.nextOffset;

		const uncompressedSizeResult = parseXzVli(indexBytes, cursor);
		if (!uncompressedSizeResult) {
			return null;
		}
		cursor = uncompressedSizeResult.nextOffset;

		uncompressedTotal += uncompressedSizeResult.value;
		if (!Number.isSafeInteger(uncompressedTotal) || cursor > crcOffset) {
			return null;
		}
	}

	while (cursor < crcOffset) {
		if (indexBytes[cursor] !== 0x00) {
			return null;
		}
		cursor += 1;
	}

	if (cursor !== crcOffset) {
		return null;
	}

	return uncompressedTotal;
}

function readXzUncompressedSize(readRange, compressedSize) {
	if (typeof readRange !== 'function' || compressedSize < XZ_STREAM_FOOTER_SIZE) {
		return null;
	}

	const footerOffset = compressedSize - XZ_STREAM_FOOTER_SIZE;
	const footer = readRange(footerOffset, XZ_STREAM_FOOTER_SIZE);
	if (!footer || footer.byteLength !== XZ_STREAM_FOOTER_SIZE) {
		return null;
	}

	if (footer[10] !== XZ_FOOTER_MAGIC_Y || footer[11] !== XZ_FOOTER_MAGIC_Z) {
		return null;
	}

	const backwardSizeRaw = readUint32LE(footer, 4);
	if (!Number.isFinite(backwardSizeRaw)) {
		return null;
	}

	const indexSize = (backwardSizeRaw + 1) * 4;
	if (!Number.isSafeInteger(indexSize) || indexSize < 8) {
		return null;
	}

	const indexOffset = footerOffset - indexSize;
	if (indexOffset < 0) {
		return null;
	}

	const indexBytes = readRange(indexOffset, indexSize);
	if (!indexBytes || indexBytes.byteLength !== indexSize) {
		return null;
	}

	return parseXzIndexUncompressedSize(indexBytes);
}

function probeXzUncompressedSize(context) {
	const compressedSize = normalizeSize(context?.compressedSize, 0);
	const readRange = context?.readRange;
	if (compressedSize <= 0 || typeof readRange !== 'function') {
		return null;
	}

	return readXzUncompressedSize(readRange, compressedSize);
}

function decodeBase64ToUint8Array(base64) {
	if (typeof Buffer !== 'undefined') {
		const buffer = Buffer.from(String(base64 || ''), 'base64');
		return new Uint8Array(buffer.buffer, buffer.byteOffset, buffer.byteLength);
	}

	if (typeof atob !== 'function') {
		throw new Error('Missing base64 decoder for xz wasm initialization');
	}

	const binary = atob(String(base64 || ''));
	const bytes = new Uint8Array(binary.length);
	for (let index = 0; index < binary.length; index++) {
		bytes[index] = binary.charCodeAt(index);
	}
	return bytes;
}

let xzWasmInstance = null;

function resolveXzWasmInstance() {
	if (xzWasmInstance) {
		return xzWasmInstance;
	}

	const wasmBytes = decodeBase64ToUint8Array(XZ_WASM_BASE64);
	const wasmModule = new WebAssembly.Module(wasmBytes);
	xzWasmInstance = new WebAssembly.Instance(wasmModule, {});
	return xzWasmInstance;
}

class XzWasmContext {
	constructor(moduleInstance) {
		if (!moduleInstance || typeof moduleInstance !== 'object' || !moduleInstance.exports) {
			throw new Error('Failed to initialize xz wasm module instance');
		}

		this.exports = moduleInstance.exports;
		this.memory = this.exports.memory;

		if (typeof this.exports.create_context !== 'function') {
			throw new Error('xz wasm module is missing create_context() export');
		}

		this.ptr = this.exports.create_context();
		if (!Number.isFinite(this.ptr) || this.ptr <= 0) {
			throw new Error('create_context() failed for xz wasm module');
		}

		this._refresh();
		this.bufSize = this.mem32[0];
		this.inStart = this.mem32[1] - this.ptr;
		this.inEnd = this.inStart + this.bufSize;
		this.outStart = this.mem32[4] - this.ptr;
		this._disposed = false;
	}

	_refresh() {
		if (this.memory.buffer !== this.mem8?.buffer) {
			this.mem8 = new Uint8Array(this.memory.buffer, this.ptr);
			this.mem32 = new Uint32Array(this.memory.buffer, this.ptr);
		}
	}

	supplyInput(sourceDataUint8Array) {
		if (this._disposed) {
			throw new Error('xz wasm context is already disposed');
		}

		const chunk = toUint8Array(sourceDataUint8Array);
		this._refresh();

		if (chunk.byteLength > this.bufSize) {
			throw new Error(`xz input chunk is too large (${chunk.byteLength} > ${this.bufSize})`);
		}

		const inBuffer = this.mem8.subarray(this.inStart, this.inEnd);
		inBuffer.set(chunk, 0);
		this.exports.supply_input(this.ptr, chunk.byteLength);
		this._refresh();
	}

	getNextOutput() {
		if (this._disposed) {
			throw new Error('xz wasm context is already disposed');
		}

		const result = this.exports.get_next_output(this.ptr);
		this._refresh();

		if (result !== XZ_OK && result !== XZ_STREAM_END) {
			throw new Error(`xz decode failed with error code ${result}`);
		}

		const outPos = this.mem32[5];
		const outChunk = this.mem8.slice(this.outStart, this.outStart + outPos);
		return {
			outChunk,
			finished: result === XZ_STREAM_END,
		};
	}

	needsMoreInput() {
		if (this._disposed) {
			return true;
		}
		this._refresh();
		return this.mem32[2] === this.mem32[3];
	}

	resetOutputBuffer() {
		if (this._disposed) {
			return;
		}
		this._refresh();
		this.mem32[5] = 0;
	}

	dispose() {
		if (this._disposed) {
			return;
		}
		this._disposed = true;

		if (typeof this.exports.destroy_context === 'function') {
			this.exports.destroy_context(this.ptr);
		}

		this.exports = null;
		this.memory = null;
		this.mem8 = null;
		this.mem32 = null;
	}
}

function createXzInflater({ onData }) {
	const context = new XzWasmContext(resolveXzWasmInstance());
	let finished = false;
	let eofSupplied = false;

	const drain = (input, inputOffsetRef, allowEof) => {
		while (!finished) {
			if (context.needsMoreInput()) {
				const remainingInput = input.byteLength - inputOffsetRef.value;
				if (remainingInput > 0) {
					const nextSize = Math.min(context.bufSize, remainingInput);
					context.supplyInput(input.subarray(inputOffsetRef.value, inputOffsetRef.value + nextSize));
					inputOffsetRef.value += nextSize;
				} else if (allowEof && !eofSupplied) {
					context.supplyInput(new Uint8Array(0));
					eofSupplied = true;
				} else {
					break;
				}
			}

			const output = context.getNextOutput();
			if (output.outChunk.byteLength > 0) {
				onData(output.outChunk);
			}
			context.resetOutputBuffer();

			if (output.finished) {
				finished = true;
				break;
			}
		}
	};

	return {
		push(chunk, isLast) {
			if (finished) {
				return;
			}

			const input = toUint8Array(chunk);
			const inputOffsetRef = { value: 0 };
			const isFinal = isLast === true;

			drain(input, inputOffsetRef, isFinal);

			if (isFinal && !finished) {
				throw new Error('xz stream ended before XZ_STREAM_END');
			}
		},
		close() {
			context.dispose();
		},
	};
}

export class XzStream extends InternalCompressedStream {
	static formatName = 'xz';
	static formatDisplayName = 'xz';
	static streamLabel = 'XzStream';

	probeUncompressedSize(context) {
		return probeXzUncompressedSize(context);
	}

	createInflater(context) {
		return createXzInflater(context);
	}
}
